22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const BLOCK_SIZE = 3;
28	const BLOCK_PRICE = 60;
29	const COMPONENT_TYPES = ["rune", "moonstone"];
30	const LOYALTY_YEARS_THRESHOLD = 2;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
44	
45	function basePremiumFor(item: ItemSpec): number {
46	  return BASE_PREMIUMS[item.type] ?? 0;
47	}
48	
49	function sumBasePremiums(items: ItemSpec[]): number {
50	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
51	}
52	
53	function countItemsOfType(items: ItemSpec[], type: string): number {
54	  return items.filter((item) => item.type === type).length;
55	}
56	
57	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
58	  const count = countItemsOfType(items, componentType);
59	  if (count !== BLOCK_SIZE) return 0;
60	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
61	}
62	
63	function blockAdjustment(items: ItemSpec[]): number {
64	  return COMPONENT_TYPES.reduce(
65	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
66	    0
67	  );
68	}
69	
70	function isHighlyEnchanted(item: ItemSpec): boolean {
71	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
72	}
73	
74	function itemSurchargeFor(item: ItemSpec): number {
75	  let surcharge = 0;
76	  if (item.cursed) surcharge += basePremiumFor(item) * CURSE_SURCHARGE_RATE;
77	  if (isHighlyEnchanted(item)) surcharge += basePremiumFor(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
78	  return surcharge;
79	}
80	
81	function sumItemSurcharges(items: ItemSpec[]): number {
82	  return items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
83	}
84	
85	function qualifiesForLoyaltyDiscount(customer: Customer): boolean {
86	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
87	}
88	
89	function loyaltyDiscountFor(customer: Customer, policyBasePremium: number): number {
90	  if (!qualifiesForLoyaltyDiscount(customer)) return 0;
91	  return policyBasePremium * LOYALTY_DISCOUNT_RATE;
92	}
93	
94	function followUpDiscountFor(customer: Customer, policyBasePremium: number): number {
95	  if ((customer.previousContracts ?? 0) <= 0) return 0;
96	  return policyBasePremium * FOLLOW_UP_DISCOUNT_RATE;
97	}
98	
99	function totalPolicyDiscount(customer: Customer, policyBasePremium: number): number {
100	  return (
101	    loyaltyDiscountFor(customer, policyBasePremium) +
102	    followUpDiscountFor(customer, policyBasePremium)
103	  );
104	}
105	
106	export function quote(input: QuoteInput): QuoteResult {
107	  const items = input.items;
108	  for (const item of items) {
109	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
110	      throw new Error(`Unknown item type: ${item.type}`);
111	    }
112	  }
113	  const policyBasePremium = sumBasePremiums(items) + blockAdjustment(items);
114	  const itemSurcharges = sumItemSurcharges(items);
115	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
116	  const policyDiscount = totalPolicyDiscount(input.customer, policyBasePremium);
117	  return {
118	    premium: Math.ceil(
119	      policyBasePremium + itemSurcharges + firstInsuranceSurcharge - policyDiscount + PROCESSING_FEE
120	    ),
121	  };
122	}
123	
124	export interface ClaimResult {
125	  payout: number;
126	  remainingCap: number;
127	}
128	
129	export interface DamageEntry {
130	  itemType: string;
131	  amount: number;
132	}
133	
134	export interface ClaimInput {
135	  items: ItemSpec[];
136	  damages: DamageEntry[];
137	  remainingCap?: number;
138	}
139	
140	const INSURANCE_VALUES: Record<string, number> = {
141	  sword: 1000,
142	  amulet: 600,
143	  staff: 800,
144	  potion: 400,
145	  rune: 250,
146	  moonstone: 250,
147	};
148	
149	const DEDUCTIBLE = 100;
150	const CAP_MULTIPLIER = 2;
151	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
152	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
153	
154	function insuranceValueFor(item: ItemSpec): number {
155	  return INSURANCE_VALUES[item.type] ?? 0;
156	}
157	
158	function sumInsuranceValues(items: ItemSpec[]): number {
159	  return items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
160	}
161	
162	function findMatchingItem(items: ItemSpec[], itemType: string): ItemSpec | undefined {
163	  return items.find((item) => item.type === itemType);
164	}
165	
166	function triggersHighEnchantmentRule(item: ItemSpec | undefined): boolean {
167	  const enchantment = item?.enchantment ?? 0;
168	  return enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
169	}
170	
171	function reimbursementFor(damage: DamageEntry, item: ItemSpec | undefined): number {
172	  const reimbursableAmount = triggersHighEnchantmentRule(item)
173	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
174	    : damage.amount;
175	  return Math.max(0, reimbursableAmount - DEDUCTIBLE);
176	}
177	
178	function sumReimbursements(damages: DamageEntry[], items: ItemSpec[]): number {
179	  return damages.reduce(
180	    (sum, damage) => sum + reimbursementFor(damage, findMatchingItem(items, damage.itemType)),
181	    0
182	  );
183	}
184	
185	function defaultCapFor(items: ItemSpec[]): number {
186	  return CAP_MULTIPLIER * sumInsuranceValues(items);
187	}
188	
189	export function claim(input: ClaimInput): ClaimResult {
190	  for (const damage of input.damages) {
191	    if (damage.amount < 0) {
192	      throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
193	    }
194	    if (findMatchingItem(input.items, damage.itemType) === undefined) {
195	      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
196	    }
197	  }
198	  const remainingCap = input.remainingCap ?? defaultCapFor(input.items);
199	  const totalReimbursement = sumReimbursements(input.damages, input.items);
200	  const payout = Math.floor(Math.min(totalReimbursement, remainingCap));
201	  return { payout, remainingCap: remainingCap - payout };
202	}
